import * as Holidays from 'date-holidays';
import HolidaysType from 'date-holidays';

const h = new (Holidays as unknown as typeof HolidaysType)('US', { types: ['public'] });

h.init('US', { types: ['public'] });

export interface HolidayInfo {
	name: string;
	date: string;
	type: string;
	start: Date;
	end: Date;
}

export interface HolidayWindow {
	isWithinWindow: boolean;
	daysFromHoliday: number;
	holidayName: string;
	effectMultiplier: number;
}

export class HolidayHelpers {
	static isUSHoliday(date: Date): boolean {
		const midDayTime = new Date(
			date.getFullYear(),
			date.getMonth(),
			date.getDate(),
			12,
			0,
			0,
		);
		const holiday = h.isHoliday(midDayTime);
		return Boolean(holiday);
	}
	private static readonly HOLIDAY_EFFECT_MULTIPLIERS: Record<string, number> = {
		Christmas: 2.5,
		'Christmas Day': 2.5,
		'Black Friday': 3.0,
		Thanksgiving: 1.8,
		'Thanksgiving Day': 1.8,
		'New Year': 1.5,
		"New Year's Day": 1.5,
		'Independence Day': 1.4,
		'July 4th': 1.4,
		'Memorial Day': 1.3,
		'Labor Day': 1.3,
		"Valentine's Day": 1.6,
		"Mother's Day": 1.4,
		"Father's Day": 1.4,
		Easter: 1.5,
		'Easter Sunday': 1.5,
		'Presidents Day': 1.2,
		"President's Day": 1.2,
		'Martin Luther King Jr. Day': 1.2,
		'Columbus Day': 1.2,
		'Veterans Day': 1.2,
	};

	static getHolidayInfo(date: Date): HolidayInfo | null {
		try {
			const midDayTime = new Date(
				date.getFullYear(),
				date.getMonth(),
				date.getDate(),
				12,
				0,
				0,
			);

			const holiday = h.isHoliday(midDayTime);
			if (!holiday) return null;

			const holidayData = Array.isArray(holiday) ? holiday[0] : holiday;

			if (!holidayData) return null;

			return {
				name: holidayData.name,
				date: midDayTime.toISOString().split('T')[0] ?? '',
				type: holidayData.type,
				start: holidayData.start,
				end: holidayData.end,
			};
			// eslint-disable-next-line @typescript-eslint/no-unused-vars
		} catch (error) {
			return null;
		}
	}

	static getHolidayEffectMultiplier(date: Date): number {
		try {
			const holidayInfo = this.getHolidayInfo(date);
			if (!holidayInfo) return 1.0;

			for (const [holidayName, multiplier] of Object.entries(
				this.HOLIDAY_EFFECT_MULTIPLIERS,
			)) {
				if (holidayInfo.name.toLowerCase().includes(holidayName.toLowerCase())) {
					return multiplier;
				}
			}

			return 1.2;
			// eslint-disable-next-line @typescript-eslint/no-unused-vars
		} catch (error) {
			return 1.0;
		}
	}

	static isWithinHolidayWindow(date: Date, windowDays = 3): HolidayWindow {
		try {
			const result: HolidayWindow = {
				isWithinWindow: false,
				daysFromHoliday: 0,
				holidayName: '',
				effectMultiplier: 1.0,
			};

			for (let offset = -windowDays; offset <= windowDays; offset++) {
				const checkDate = new Date(date);
				checkDate.setDate(checkDate.getDate() + offset);

				const holidayInfo = this.getHolidayInfo(checkDate);
				if (holidayInfo) {
					result.isWithinWindow = true;
					result.daysFromHoliday = Math.abs(offset);
					result.holidayName = holidayInfo.name;
					result.effectMultiplier = this.getHolidayEffectMultiplier(checkDate);

					if (offset === 0 || result.daysFromHoliday === 0) {
						break;
					}
				}
			}

			return result;
			// eslint-disable-next-line @typescript-eslint/no-unused-vars
		} catch (error) {
			return {
				isWithinWindow: false,
				daysFromHoliday: 0,
				holidayName: '',
				effectMultiplier: 1.0,
			};
		}
	}

	static getHolidaysForYear(year: number): HolidayInfo[] {
		try {
			const holidays: HolidayInfo[] = [];
			const startDate = new Date(year, 0, 1);
			const endDate = new Date(year, 11, 31);

			const currentDate = new Date(startDate);
			while (currentDate <= endDate) {
				const holidayInfo = this.getHolidayInfo(currentDate);
				if (holidayInfo) {
					const exists = holidays.some(
						(h) => h.name === holidayInfo.name && h.date === holidayInfo.date,
					);
					if (!exists) {
						holidays.push(holidayInfo);
					}
				}
				currentDate.setDate(currentDate.getDate() + 1);
			}

			return holidays.sort(
				(a, b) => new Date(a.date).getTime() - new Date(b.date).getTime(),
			);
			// eslint-disable-next-line @typescript-eslint/no-unused-vars
		} catch (error) {
			return [];
		}
	}

	static getHolidayEffect(date: Date): number {
		const windowInfo = this.isWithinHolidayWindow(date, 3);

		if (!windowInfo.isWithinWindow) {
			return 1.0;
		}

		const distanceEffect = Math.max(0, 1 - windowInfo.daysFromHoliday / 3);
		const baseMultiplier = windowInfo.effectMultiplier - 1;

		return 1.0 + baseMultiplier * distanceEffect;
	}

	static isBlackFriday(date: Date): boolean {
		try {
			if (isNaN(date.getTime())) {
				return false;
			}

			const year = date.getFullYear();

			let firstThursday = 1;
			let safety = 0;
			while (new Date(year, 10, firstThursday).getDay() !== 4 && safety < 7) {
				firstThursday++;
				safety++;
			}

			if (safety >= 7) {
				return false;
			}

			const thanksgiving = new Date(year, 10, firstThursday + 21);
			const blackFriday = new Date(thanksgiving);
			blackFriday.setDate(blackFriday.getDate() + 1);

			return date.toDateString() === blackFriday.toDateString();
		} catch {
			return false;
		}
	}

	static formatHolidayData(holidays: HolidayInfo[]): {
		date: string;
		effect_window: number;
		impact_multiplier: number;
		name: string;
	}[] {
		return holidays.map((holiday) => {
			try {
				const [year, month, day] = holiday.date.split('-').map(Number);

				if (!year || !month || !day) {
					throw new Error('Invalid date format');
				}

				const localDate = new Date(year, month - 1, day, 12, 0, 0);

				return {
					date: holiday.date,
					effect_window: 6,
					impact_multiplier: this.getHolidayEffectMultiplier(localDate),
					name: holiday.name,
				};
			} catch {
				// Fallback for invalid dates - return default multiplier
				return {
					date: holiday.date,
					effect_window: 6,
					impact_multiplier: 1.0,
					name: holiday.name,
				};
			}
		});
	}
}

// Backward compatibility export
export const isUSHoliday = (date: Date): boolean => HolidayHelpers.isUSHoliday(date);

