     1→export interface TrendingScoreData {
     2→	historicalOrders: number[];
     3→	forecastedOrders: number[];
     4→	trendComponent: number[];
     5→}
     6→
     7→export interface TrendingScoreResult {
     8→	trendScore: number;
     9→	isSignificant: boolean;
    10→	pValue: number;
    11→	effectSize: number;
    12→	momentum: number;
    13→	volatility: number;
    14→}
    15→
    16→export class TrendingScoreCalculator {
    17→	private static readonly SIGNIFICANCE_THRESHOLD = 0.05;
    18→	private static readonly MIN_EFFECT_SIZE = 0.3;
    19→	private static readonly MOMENTUM_WEIGHT = 0.6;
    20→	private static readonly SIGNIFICANCE_WEIGHT = 0.4;
    21→
    22→	static calculateTrendingScore(data: TrendingScoreData): TrendingScoreResult {
    23→		const { historicalOrders, forecastedOrders, trendComponent } = data;
    24→
    25→		if (historicalOrders.length === 0 || forecastedOrders.length === 0) {
    26→			return this.createEmptyResult();
    27→		}
    28→
    29→		const historicalStats = this.calculateStatistics(historicalOrders);
    30→		const forecastStats = this.calculateStatistics(forecastedOrders);
    31→
    32→		const tTestResult = this.performTTest(historicalStats, forecastStats);
    33→		const effectSize = this.calculateEffectSize(historicalStats, forecastStats);
    34→		const momentum = this.calculateMomentum(trendComponent);
    35→		const volatility = this.calculateVolatility(historicalOrders);
    36→
    37→		const isSignificant =
    38→			tTestResult.pValue < this.SIGNIFICANCE_THRESHOLD &&
    39→			Math.abs(effectSize) > this.MIN_EFFECT_SIZE;
    40→
    41→		let trendScore = 0;
    42→		if (isSignificant && effectSize > 0) {
    43→			const momentumFactor = Math.max(0, momentum * 20);
    44→			const significanceFactor = Math.max(0, effectSize * 30);
    45→
    46→			trendScore =
    47→				momentumFactor * this.MOMENTUM_WEIGHT +
    48→				significanceFactor * this.SIGNIFICANCE_WEIGHT;
    49→
    50→			trendScore = this.applyVolatilityPenalty(trendScore, volatility);
    51→		}
    52→
    53→		return {
    54→			trendScore: Math.round(Math.max(0, Math.min(100, trendScore)) * 100) / 100,
    55→			isSignificant,
    56→			pValue: tTestResult.pValue,
    57→			effectSize,
    58→			momentum,
    59→			volatility,
    60→		};
    61→	}
    62→
    63→	private static calculateStatistics(values: number[]): {
    64→		mean: number;
    65→		variance: number;
    66→		stdDev: number;
    67→		n: number;
    68→	} {
    69→		const n = values.length;
    70→		if (n === 0) {
    71→			return { mean: 0, variance: 0, stdDev: 0, n: 0 };
    72→		}
    73→
    74→		const mean = values.reduce((sum, val) => sum + val, 0) / n;
    75→		const variance =
    76→			values.reduce((sum, val) => sum + Math.pow(val - mean, 2), 0) / (n - 1);
    77→		const stdDev = Math.sqrt(Math.max(0, variance));
    78→
    79→		return { mean, variance, stdDev, n };
    80→	}
    81→
    82→	private static performTTest(
    83→		group1: { mean: number; variance: number; n: number },
    84→		group2: { mean: number; variance: number; n: number },
    85→	): { tStatistic: number; pValue: number } {
    86→		if (group1.n <= 1 || group2.n <= 1) {
    87→			return { tStatistic: 0, pValue: 1.0 };
    88→		}
    89→
    90→		const pooledVariance =
    91→			((group1.n - 1) * group1.variance + (group2.n - 1) * group2.variance) /
    92→			(group1.n + group2.n - 2);
    93→
    94→		if (pooledVariance <= 0) {
    95→			return { tStatistic: 0, pValue: 1.0 };
    96→		}
    97→
    98→		const standardError = Math.sqrt(pooledVariance * (1 / group1.n + 1 / group2.n));
    99→		const tStatistic = (group2.mean - group1.mean) / standardError;
   100→		const degreesOfFreedom = group1.n + group2.n - 2;
   101→
   102→		const pValue = this.calculatePValue(Math.abs(tStatistic), degreesOfFreedom);
   103→
   104→		return { tStatistic, pValue };
   105→	}
   106→
   107→	private static calculatePValue(tStatistic: number, degreesOfFreedom: number): number {
   108→		if (degreesOfFreedom <= 0) return 1.0;
   109→		if (tStatistic === 0) return 1.0;
   110→
   111→		const betaDistributionInput =
   112→			degreesOfFreedom / (degreesOfFreedom + tStatistic * tStatistic);
   113→
   114→		if (
   115→			betaDistributionInput < 0 ||
   116→			betaDistributionInput > 1 ||
   117→			!Number.isFinite(betaDistributionInput)
   118→		)
   119→			return 1.0;
   120→
   121→		const betaValue = this.incompleteBeta(
   122→			betaDistributionInput,
   123→			degreesOfFreedom / 2,
   124→			0.5,
   125→		);
   126→
   127→		return Math.max(0, Math.min(1, betaValue));
   128→	}
   129→
   130→	private static incompleteBeta(
   131→		inputX: number,
   132→		alphaParameter: number,
   133→		betaParameter: number,
   134→	): number {
   135→		if (inputX <= 0) return 0;
   136→		if (inputX >= 1) return 1;
   137→
   138→		const betaFunction = Math.exp(
   139→			this.gammaLn(alphaParameter + betaParameter) -
   140→				this.gammaLn(alphaParameter) -
   141→				this.gammaLn(betaParameter) +
   142→				alphaParameter * Math.log(inputX) +
   143→				betaParameter * Math.log(1 - inputX),
   144→		);
   145→
   146→		if (inputX < (alphaParameter + 1) / (alphaParameter + betaParameter + 2)) {
   147→			return (
   148→				(betaFunction *
   149→					this.betaContinuedFraction(inputX, alphaParameter, betaParameter)) /
   150→				alphaParameter
   151→			);
   152→		} else {
   153→			return (
