			const mockDate = new Date(2024, 10, 1);

			const originalGetDay = Date.prototype.getDay;
			let callCount = 0;

			Date.prototype.getDay = function (this: Date): number {
				if (
					this.getFullYear() === 2024 &&
					this.getMonth() === 10 &&
					this.getDate() <= 7
				) {
					callCount++;
					if (callCount > 10) {
						return 4;
					}
					return 0;
				}
				return originalGetDay.call(this);
			};

			const result = HolidayHelpers.isBlackFriday(mockDate);
			expect(result).toBe(false);

			Date.prototype.getDay = originalGetDay;
		});
	});

