			expect(formatted[0]).toEqual({
				date: 'invalid-date',
				effect_window: 6,
				impact_multiplier: 1.0,
				name: 'Invalid Holiday',
			});
		});
	});

	describe('Integration tests', () => {
		it('should work consistently across different methods', () => {
			const christmasDate = createLocalDate(2024, 12, 25);

			// All methods should recognize Christmas
			expect(HolidayHelpers.isUSHoliday(christmasDate)).toBe(true);
			expect(HolidayHelpers.getHolidayInfo(christmasDate)).toBeTruthy();
			expect(HolidayHelpers.getHolidayEffectMultiplier(christmasDate)).toBe(2.5);
			expect(HolidayHelpers.getHolidayEffect(christmasDate)).toBeGreaterThan(1.0);

			const window = HolidayHelpers.isWithinHolidayWindow(christmasDate);
			expect(window.isWithinWindow).toBe(true);
			expect(window.daysFromHoliday).toBe(0);
		});

		it('should work consistently for non-holidays', () => {
			const regularDate = createLocalDate(2024, 3, 15);

			// All methods should not recognize regular dates
			expect(HolidayHelpers.isUSHoliday(regularDate)).toBe(false);
			expect(HolidayHelpers.getHolidayInfo(regularDate)).toBeNull();
