					expect(HolidayHelpers.isUSHoliday(createLocalDate(2024, 1, 1))).toBe(true);
					expect(HolidayHelpers.isUSHoliday(createLocalDate(2025, 1, 1))).toBe(true);

					// Test backward compatibility function
