static getHolidayEffectMultiplier(date: Date): number {
	try {
		const holidayInfo = this.getHolidayInfo(date);
		if (!holidayInfo) return 1.0;

		for (const [holidayName, multiplier] of Object.entries(
			this.HOLIDAY_EFFECT_MULTIPLIERS,
		)) {
			if (holidayInfo.name.toLowerCase().includes(holidayName.toLowerCase())) {
				return multiplier;
			}
		}

		return 1.2;
		// eslint-disable-next-line @typescript-eslint/no-unused-vars
	} catch (error) {
		return 1.0;
	}
}

