				let numeratorC = 1;
				let denominatorD = epsilon / 2;

				if (Math.abs(denominatorD) < epsilon) denominatorD = epsilon;
				denominatorD = 1 / denominatorD;
				let resultH = denominatorD;

				for (let iteration = 1; iteration <= 2; iteration++) {
					denominatorD = epsilon / 2;
