					denominatorD = epsilon / 2;
					numeratorC = epsilon / 2;

					if (Math.abs(denominatorD) < epsilon) denominatorD = epsilon;
					if (Math.abs(numeratorC) < epsilon) numeratorC = epsilon;
					denominatorD = 1 / denominatorD;
					const deltaValue = denominatorD * numeratorC;
					resultH *= deltaValue;

